import java.util.Random;import java.util.Scanner;public class Main {    public static void main(String[] args) {        Scanner input = new Scanner(System.in);        while(true){            try {                System.out.println("1. Play\n2. Exit");                int play =  input.nextInt();                input.nextLine();                if (play == 1){                    int i = 0;                    int random = generateRandom();                    while (i < 3){                        System.out.println("Guess a number [1-10]: ");                        int guess = input.nextInt();                        input.nextLine();                        if (guess >= 1 &&  guess <= 10){                            if (guess == random){                                System.out.println("Congratulations! You guessed it!");                                break;                            }                            else {                                if (guess > random)                                    System.out.println("Wrong guess! Too High!");                                else                                    System.out.println("Wrong guess! Too Low!");                                i++;                                if (i == 3){                                    System.out.println("Game Over! Right Answer was: " + random);                                    break;                                }                            }                        }                        else                            System.out.println("Your number is not between 1 and 10!");                    }                }                else if (play == 2){break;}                else{System.out.println("Choose between 1 and 2");}            }            catch (Exception e){                System.out.println("Letters is not allowed");                input.nextLine();            }        }            input.close();    }    public static int generateRandom() {        Random rand = new Random();        return rand.nextInt(10) + 1;    }}